node - <<'NODE'
const resources = [
  {id:'R3', cap:41, cost:17},
  {id:'R1', cap:46, cost:21},
  {id:'R2', cap:64, cost:27},
];
const totalDemand = 33 + 51 + 28;
const totalCapacity = resources.reduce((a, b) => a + b.cap, 0);
let remaining = totalDemand;
let cost = 0;
const allocation = [];
for (const r of resources) {
  const take = Math.min(r.cap, remaining);
  allocation.push({id: r.id, qty: take, cost: take * r.cost});
  remaining -= take;
  cost += take * r.cost;
}
console.log(JSON.stringify({totalDemand, totalCapacity, remaining, allocation, cost}, null, 2));
NODE

